const body = $input.first().json.body || $input.first().json;
const isHumanTakeover = $input.first().json.isHumanTakeover || false;

const fromRaw = body?.payload?.from || '';
let phone;
if (fromRaw.includes('@lid')) {
  phone = fromRaw;
} else {
  phone = fromRaw.replace('@c.us', '').replace('@s.whatsapp.net', '');
}

const message = body?.payload?.body || '';
const session = body?.payload?.sessionName || 'default';

return [{ json: { phone, message, session, isHumanTakeover } }];

const extracted = $('📋 Extrair Dados WAHA').first()?.json || {};
const sessionRow = $('🗃️ Buscar Sessão Usuário').first()?.json || null;

const phone = extracted.phone;
const message = extracted.message;
const session = extracted.session;
const isHumanTakeover = extracted.isHumanTakeover || false;
const nicho = sessionRow?.nicho || null;
const bot_paused_until = sessionRow?.bot_paused_until || null;

let historico = [];
if (sessionRow?.historico) {
  if (typeof sessionRow.historico === 'string') {
    try { historico = JSON.parse(sessionRow.historico); } catch(e) { historico = []; }
  } else if (Array.isArray(sessionRow.historico)) {
    historico = sessionRow.historico;
  }
}

return [{ json: { phone, message, session, isHumanTakeover, nicho, historico, bot_paused_until } }];

const extracted = $('📋 Extrair Dados WAHA').first()?.json || {};
const sessionRow = $('🗃️ Buscar Sessão Usuário').first()?.json || null;
const isHumanTakeover = extracted.isHumanTakeover || false;
const botPausedUntil = sessionRow?.bot_paused_until ? new Date(sessionRow.bot_paused_until) : null;
const phone = extracted.phone;
const message = extracted.message || '';

if (isHumanTakeover) { return [{ json: { phone, message, isPaused: true, humanTakeover: true, mensagens_formatadas: [] } }]; }
if (botPausedUntil && new Date() < botPausedUntil) { return []; }

let historico = [];
if (sessionRow?.historico) {
  if (typeof sessionRow.historico === 'string') { try { historico = JSON.parse(sessionRow.historico); } catch(e) {} }
  else if (Array.isArray(sessionRow.historico)) { historico = sessionRow.historico; }
}

const RUIDO = ['[ENCERRADO]', '[object Object]', 'undefined', 'null', 'ERROR:'];
const historico_limpo = historico.filter(function(h) {
  return h && h.role && typeof h.content === 'string' && h.content.trim() !== '' &&
         (h.role === 'user' || h.role === 'assistant') &&
         !RUIDO.some(function(p) { return h.content.includes(p); });
});

const assistantCount = historico_limpo.filter(function(h) { return h.role === 'assistant'; }).length;
const msgLower = message.toLowerCase();
const isNao = ['nao', 'não', 'ainda nao', 'ainda não', 'agora nao', 'duvida', 'como', 'quem'].some(function(w) { return msgLower.includes(w); });
const isSim = ['sim', 'quero', 'pode', 'bora', 'com certeza', 'ok', 'manda', 'interessa'].some(function(w) { return msgLower.includes(w); });

let stage = 'APRESENTACAO';
if (assistantCount === 0) { stage = 'APRESENTACAO'; }
else if (assistantCount >= 1 && assistantCount <= 2) { if (isNao) stage = 'OBJECAO'; else stage = 'DOUTRINACAO'; }
else if (assistantCount === 3) { if (isNao) stage = 'OBJECAO'; else stage = 'FECHAMENTO'; }
else { if (isNao || !isSim) stage = 'OBJECAO'; else stage = 'FINALIZACAO'; }

const stageDirective = '[DIRETIVA DO SISTEMA]\nVOCE ESTA NA FASE: ' + stage + '\nVEJA NO SEU ROTEIRO QUAL É O TEXTO EXATO DA FASE ' + stage + ' E RESPONDA USANDO ELE. LEMBRE-SE DO ESPAÇAMENTO OBRIGATÓRIO (DUPLO ENTER).';

const historico_limitado = historico_limpo.slice(-10);
const mensagens = historico_limitado.map(function(h) { return { role: h.role, content: h.content }; });
mensagens.push({ role: 'user', content: message });

return [{ json: { phone, message, session: extracted.session, nicho: sessionRow?.nicho, isPaused: false, mensagens_formatadas: mensagens, stageDirective: stageDirective, current_stage: stage } }];

let aiResponseRaw = '';
try { aiResponseRaw = aiResponseRaw || $('📡 Chamar Claude MKT').first()?.json?.content?.[0]?.text; } catch (e) {}
aiResponseRaw = (aiResponseRaw || '').trim();
const phone = $('📋 Extrair Dados WAHA').first().json.phone;
const isEncerrado = aiResponseRaw.includes('[ENCERRADO]');
let textoLimpo = aiResponseRaw.replace(/\[.*?\]/g, '').trim();
if (!textoLimpo || textoLimpo.length < 5) {
    if (aiResponseRaw.length > 10 && !isEncerrado) { textoLimpo = aiResponseRaw.replace(/\[ENCERRADO\]/g, '').trim(); }
    else { textoLimpo = 'Entendido, vou verificar isso para você.'; }
}
return [{ json: { isEncerrado, textoLimpo, phone } }];

